Javascript.validate:
   
	var val = Services.getValue(ProvisionalAssessmentCosts.dataBinding);
	var err = validateCurrencyValue(val, 5000.00, true);
	if( null == err )
	{
		Services.setValue(ProvisionalAssessmentCosts.dataBinding, WPU.formatToTwoDP(val));
	}
	return err;

